 * Tests for PerformanceStats RSC section
 *
 * Requirements (from PRD):
 * - Table with 4 rows: verify, verify_with_msg_point, hash_to_point, NTT-512
 * - Step counts: 63,177 / 26,301 / 5,988 / ~15,000
 * - L2 gas costs: ~13.2M / ~5.5M / ~1.3M / ~3.1M
 * - Calldata efficiency card: 17x reduction (62 vs ~1,030 felts)
 * - Zero client JS (pure RSC)
 */

import { describe, test, expect } from "bun:test"
import React from "react"
import { renderToStaticMarkup } from "react-dom/server"
import { PerformanceStats } from "../../components/landing/PerformanceStats"

function renderPerformanceStats(): string {
  return renderToStaticMarkup(React.createElement(PerformanceStats))
}

describe("PerformanceStats Section (RSC)", () => {
  test("renders heading text exactly 'Performance Stats'", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("Performance Stats")
  })

  test("renders a table with exactly 4 body rows", () => {
    const html = renderPerformanceStats()
    const rowCount = (html.match(/<tr/g) ?? []).length
    // 4 body rows + 1 header row = 5 total tr elements
    expect(rowCount).toBeGreaterThanOrEqual(4)
    // Verify each operation name appears
    expect(html).toContain("verify")
    expect(html).toContain("verify_with_msg_point")
    expect(html).toContain("hash_to_point")
    expect(html).toContain("NTT-512")
  })

  test("includes table caption with benchmark context text", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("<caption")
    expect(html).toContain("Falcon-512")
  })

  test("renders 3 th elements with scope='col'", () => {
    const html = renderPerformanceStats()
    const scopeColCount = (html.match(/scope="col"/g) ?? []).length
    expect(scopeColCount).toBe(3)
  })

  test("renders verify row with exact step and gas strings", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("63,177")
    expect(html).toContain("~13.2M L2")
  })

  test("renders verify_with_msg_point row with exact step and gas strings", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("verify_with_msg_point")
    expect(html).toContain("26,301")
    expect(html).toContain("~5.5M L2")
  })

  test("renders hash_to_point row with exact step and gas strings", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("hash_to_point")
    expect(html).toContain("5,988")
    expect(html).toContain("~1.3M L2")
  })

  test("renders NTT-512 row with exact step and gas strings", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("NTT-512")
    expect(html).toContain("~15,000")
    expect(html).toContain("~3.1M L2")
  })

  test("applies font-mono class to operation name cells", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("font-mono")
  })

  test("renders calldata card with 17x reduction and 62 vs ~1,030 felts", () => {
    const html = renderPerformanceStats()
    expect(html).toContain("17x reduction")
    expect(html).toContain("62 vs ~1,030 felts")
  })

  test("contains no use client directive (RSC constraint)", () => {
    // Read the source file to ensure no "use client" directive
    const fs = require("fs")
    const source = fs.readFileSync(
      new URL("../../components/landing/PerformanceStats.tsx", import.meta.url),
      "utf-8"
    )
    expect(source).not.toContain('"use client"')
    expect(source).not.toContain("'use client'")
  })

  test("renders without inline script tags (zero client JS as RSC)", () => {
    const html = renderPerformanceStats()
    expect(html).not.toContain("<script")
  })
})

