import { mock } from "bun:test"
import React from "react"

type DynamicOptions = {
  readonly ssr?: boolean
  readonly loading?: () => React.ReactNode
}

declare global {
  var __nextDynamicCalls: DynamicOptions[]
}

globalThis.__nextDynamicCalls = []

mock.module("next/dynamic", () => ({
  default: (_loader: () => Promise<unknown>, options?: DynamicOptions) => {
    globalThis.__nextDynamicCalls.push({
      ssr: options?.ssr,
      loading: options?.loading,
    })

    function DynamicStub(): React.JSX.Element {
      if (options?.loading) {
        return React.createElement(React.Fragment, null, options.loading())
      }
      return React.createElement("div", { "data-testid": "dynamic-stub" })
    }

    return DynamicStub
  },
}))

