    for (const call of globalThis.__nextDynamicCalls) {
      expect(call.ssr).toBe(false)
    }
  })

  test("renders skeleton fallbacks for all interactive sections", () => {
    const html = renderHome()

    expect(html.match(/animate-pulse/g)?.length ?? 0).toBe(3)
    expect(html).toContain("Verification Playground")
    expect(html).toContain("Pipeline Deep-Dive")
    expect(html).toContain("Deploy Account")
  })
