type PerformanceRow = { operation: string; steps: string; gas: string }

const PERFORMANCE_ROWS: readonly PerformanceRow[] = [
  { operation: "verify", steps: "63,177", gas: "~13.2M L2" },
  { operation: "verify_with_msg_point", steps: "26,301", gas: "~5.5M L2" },
  { operation: "hash_to_point", steps: "5,988", gas: "~1.3M L2" },
  { operation: "NTT-512", steps: "~15,000", gas: "~3.1M L2" },
]

export function PerformanceStats(): React.JSX.Element {

import { describe, expect, test } from "bun:test"
import React from "react"
import { renderToStaticMarkup } from "react-dom/server"
import Home from "../../app/page"

function renderHome(): string {
  return renderToStaticMarkup(React.createElement(Home))
}

describe("Home landing page composition", () => {
  test("renders all 6 sections in the expected order", () => {
    const html = renderHome()
    const markers = [
      'id="hero"',
      'id="why-post-quantum"',
      'id="performance-stats"',
      'id="verify"',
      'id="pipeline"',
      'id="deploy"',
    ]

    let previousIndex = -1
    for (const marker of markers) {
      const currentIndex = html.indexOf(marker)
      expect(currentIndex).toBeGreaterThan(previousIndex)
      previousIndex = currentIndex
    }
  })

  test("configures interactive sections through next/dynamic with ssr disabled", () => {
    renderHome()

    expect(globalThis.__nextDynamicCalls).toHaveLength(3)
    for (const call of globalThis.__nextDynamicCalls) {
      expect(call.ssr).toBe(false)
    }
  })

  test("renders skeleton fallbacks for all interactive sections", () => {
    const html = renderHome()

    expect(html.match(/animate-pulse/g)?.length ?? 0).toBe(3)
    expect(html).toContain("Verification Playground")
    expect(html).toContain("Pipeline Deep-Dive")
    expect(html).toContain("Deploy Account")
  })
})

